import Foundation

let appName = "321Doit"
let appAuthor = "毛鑫涛 / Mao Xintao"
// The running app's Info.plist is generated by build.sh, so it is the single
// source of truth for release metadata. Command-line smoke tests do not have an
// app bundle and therefore use the current internal-build values as
// deterministic fallbacks. Tools/check_internal_version.sh prevents these
// values from drifting away from build.sh.
let appVersionString = Bundle.main.object(forInfoDictionaryKey: "CFBundleShortVersionString") as? String ?? "0.7"
let appBuildNumberString = Bundle.main.object(forInfoDictionaryKey: "CFBundleVersion") as? String ?? "1"

/// Numeric macOS version with the build tag, language-neutral.
/// `ProcessInfo.operatingSystemVersionString` returns Apple's localized
/// "Version 15.3 (Build 24D60)" / "版本 15.3（版本 24D60）" form, which leaks
/// Chinese into English UI when the user's macOS UI language is Chinese.
func osVersionDisplay() -> String {
    let v = ProcessInfo.processInfo.operatingSystemVersion
    var version = "\(v.majorVersion).\(v.minorVersion)"
    if v.patchVersion != 0 {
        version += ".\(v.patchVersion)"
    }
    var size = 0
    sysctlbyname("kern.osversion", nil, &size, nil, 0)
    if size > 0 {
        var buffer = [CChar](repeating: 0, count: size)
        if sysctlbyname("kern.osversion", &buffer, &size, nil, 0) == 0 {
            let build = String(cString: buffer).trimmingCharacters(in: .whitespacesAndNewlines)
            if !build.isEmpty {
                return "\(version) (\(build))"
            }
        }
    }
    return version
}


// MARK: - Transcode profile

enum TranscodeCodec: String, CaseIterable, Equatable, Codable, Identifiable {
    case proresProxy
    case proresLT
    case prores422
    case prores422HQ
    case prores4444
    case prores4444XQ
    case h264
    case h265
    case h266

    var id: String { rawValue }

    var displayName: String {
        switch self {
        case .proresProxy:   return "ProRes 422 Proxy"
        case .proresLT:      return "ProRes 422 LT"
        case .prores422:     return "ProRes 422"
        case .prores422HQ:   return "ProRes 422 HQ"
        case .prores4444:    return "ProRes 4444"
        case .prores4444XQ:  return "ProRes 4444 XQ"
        case .h264:          return "H.264 / AVC"
        case .h265:          return "H.265 / HEVC"
        case .h266:          return "H.266 / VVC"
        }
    }

    var shortLabel: String {
        switch self {
        case .proresProxy:   return "PRX"
        case .proresLT:      return "LT"
        case .prores422:     return "422"
        case .prores422HQ:   return "HQ"
        case .prores4444:    return "4444"
        case .prores4444XQ:  return "XQ"
        case .h264:          return "H.264"
        case .h265:          return "HEVC"
        case .h266:          return "VVC"
        }
    }

    var family: String {
        switch self {
        case .proresProxy, .proresLT, .prores422, .prores422HQ, .prores4444, .prores4444XQ:
            return "Apple ProRes"
        case .h264:  return "H.264 (AVC)"
        case .h265:  return "H.265 (HEVC)"
        case .h266:  return "H.266 (VVC)"
        }
    }

    var isProRes: Bool {
        switch self {
        case .h264, .h265, .h266: return false
        default: return true
        }
    }

    var fileExtension: String {
        isProRes ? "mov" : "mp4"
    }

    var fileSuffix: String {
        switch self {
        case .proresProxy:   return "_proxy_prores"
        case .proresLT:      return "_proxy_prores_lt"
        case .prores422:     return "_proxy_prores_422"
        case .prores422HQ:   return "_proxy_prores_hq"
        case .prores4444:    return "_proxy_prores_4444"
        case .prores4444XQ:  return "_proxy_prores_xq"
        case .h264:          return "_proxy_h264"
        case .h265:          return "_proxy_h265"
        case .h266:          return "_proxy_h266"
        }
    }

    var folderName: String {
        switch self {
        case .proresProxy:   return "ProResProxy"
        case .proresLT:      return "ProResLT"
        case .prores422:     return "ProRes422"
        case .prores422HQ:   return "ProRes422HQ"
        case .prores4444:    return "ProRes4444"
        case .prores4444XQ:  return "ProRes4444XQ"
        case .h264:          return "H264"
        case .h265:          return "H265"
        case .h266:          return "H266"
        }
    }
}

