struct BurnInFieldToggles: Codable, Equatable {
    var fileName: Bool = true
    var timecode: Bool = true
    var reelOrCard: Bool = true
    var cameraID: Bool = false
    var clipName: Bool = false
    var resolution: Bool = false
    var frameRate: Bool = false
    var lutName: Bool = false
    var projectName: Bool = false
    var shootDay: Bool = false
}

struct BurnInSettings: Codable, Equatable {
    var enabled: Bool = false
    var fields: BurnInFieldToggles = .init()
    var position: BurnInPosition = .bottomLeft
    var size: BurnInSize = .medium
    var target: BurnInTarget = .proxyTranscode

    init() {}

    private enum CodingKeys: String, CodingKey {
        case enabled, fields, position, size, target
    }

    init(from decoder: Decoder) throws {
        let c = try decoder.container(keyedBy: CodingKeys.self)
        enabled = try c.decodeIfPresent(Bool.self, forKey: .enabled) ?? false
        fields = try c.decodeIfPresent(BurnInFieldToggles.self, forKey: .fields) ?? .init()
        position = try c.decodeIfPresent(BurnInPosition.self, forKey: .position) ?? .bottomLeft
        size = try c.decodeIfPresent(BurnInSize.self, forKey: .size) ?? .medium
        target = try c.decodeIfPresent(BurnInTarget.self, forKey: .target) ?? .proxyTranscode
    }
}

