// MARK: - Checksum
// `ChecksumAlgorithm`, `XXHash64Implementation`, and `formatHash` now live in
// ChecksumTypes.swift so they can be shared by every 321Doit tool.

struct TranscodeProfile: Equatable, Codable {
    var codec: TranscodeCodec
    var quality: TranscodeQuality
    var bitrate: TranscodeBitrate
    var scale: TranscodeScale
    var attemptRaw: Bool
    var enableHardwareAcceleration: Bool = true
    var ffmpegPath: String? = nil
    
    var lutMode: LUTMode = .none
    /// Path to a .cube / .3dl LUT file.
    var lutPath: String? = nil
    /// 0...1 — interpolation between source (0) and full LUT (1).
    var lutIntensity: Double = 1.0

    var burnIn: BurnInSettings = .init()
    var frameExtraction: FrameExtractionSettings = .init()

    static let `default` = TranscodeProfile(
        codec: .proresProxy,
        quality: .medium,
        bitrate: .auto,
        scale: .hd1080,
        attemptRaw: false,
        enableHardwareAcceleration: true,
        ffmpegPath: nil,
        lutMode: .none,
        lutPath: nil,
        lutIntensity: 1.0,
        burnIn: .init()
    )

    var summary: String {
        var parts = [codec.displayName]
        if !codec.isProRes {
            if bitrate == .auto {
                parts.append(quality.displayName)
            } else {
                parts.append(bitrate.displayName)
            }
        }
        parts.append(scale.displayName)
        return parts.joined(separator: " · ")
    }
}

enum ProjectAssociationMode: String, Codable, Equatable {
    case independent
    case linkedProject
}

struct OffloadSettings: Codable, Equatable {
    var taskID: UUID = UUID()
    var projectAssociationMode: ProjectAssociationMode = .independent
    var linkedProjectID: UUID?
    var projectName: String
    var cardNumber: String
    var operatorName: String
    var camera: String
    var location: String
    var notes: String
    var sourceURL: URL
    var targetRoots: [URL]
    var createdAt: Date
    var generateProxies: Bool
    var transcodeProfile: TranscodeProfile = .default
    var language: AppLanguage = .system
    var checksumAlgorithm: ChecksumAlgorithm = .xxhash64
    var xxHash64Implementation: XXHash64Implementation = .automatic
    var copyBufferKB: Int = 1024
    var writeSidecarChecksum: Bool = true
    var generateAscMHL: Bool = true
    var generateCSVLog: Bool = true
    var generateJSONLog: Bool = true
    var generateTXTBrief: Bool = true
    var recordEnvironmentInReport: Bool = true
    var sourceCardProfile: CameraCardProfile = .unknown
    var verifyOnly: Bool = false
    var checksumRetryCount: Int = 0
    var enableSpeedLimit: Bool = false
    var speedLimitMBps: Int = 200
    var resumedFromJournal: Bool = false
    var strictResume: Bool = true
    var ioRetryCount: Int = 3
    /// Snapshot of post-handoff settings at job start (decoupled from live preferences).
    var handoff: HandoffSettings = .init()
    /// One job can write one or more package layouts. If more than one is
    /// selected, sibling output folders receive stable suffixes.
    var outputPackageModes: [OffloadPackageMode] = [.safeCopy]

    init(
        projectName: String,
        cardNumber: String,
        operatorName: String,
        camera: String,
        location: String,
        notes: String,
        sourceURL: URL,
        targetRoots: [URL],
        createdAt: Date,
        generateProxies: Bool,
        transcodeProfile: TranscodeProfile = .default,
        language: AppLanguage = .system,
        checksumAlgorithm: ChecksumAlgorithm = .xxhash64,
        xxHash64Implementation: XXHash64Implementation = .automatic,
        copyBufferKB: Int = 1024,
        writeSidecarChecksum: Bool = true,
        generateAscMHL: Bool = true,
        generateCSVLog: Bool = true,
        generateJSONLog: Bool = true,
        generateTXTBrief: Bool = true,
        recordEnvironmentInReport: Bool = true,
        sourceCardProfile: CameraCardProfile = .unknown,
        verifyOnly: Bool = false,
        checksumRetryCount: Int = 0,
        enableSpeedLimit: Bool = false,
        speedLimitMBps: Int = 200,
        resumedFromJournal: Bool = false,
        strictResume: Bool = true,
        ioRetryCount: Int = 3,
        handoff: HandoffSettings = .init(),
        outputPackageModes: [OffloadPackageMode] = [.safeCopy],
        taskID: UUID = UUID(),
        projectAssociationMode: ProjectAssociationMode = .independent,
        linkedProjectID: UUID? = nil
    ) {
        self.taskID = taskID
        self.projectAssociationMode = projectAssociationMode
        self.linkedProjectID = linkedProjectID
        self.projectName = projectName
        self.cardNumber = cardNumber
        self.operatorName = operatorName
        self.camera = camera
        self.location = location
        self.notes = notes
        self.sourceURL = sourceURL
        self.targetRoots = targetRoots
        self.createdAt = createdAt
        self.generateProxies = generateProxies
        self.transcodeProfile = transcodeProfile
        self.language = language
        self.checksumAlgorithm = checksumAlgorithm
        self.xxHash64Implementation = xxHash64Implementation
        self.copyBufferKB = copyBufferKB
        self.writeSidecarChecksum = writeSidecarChecksum
        self.generateAscMHL = generateAscMHL
        self.generateCSVLog = generateCSVLog
        self.generateJSONLog = generateJSONLog
        self.generateTXTBrief = generateTXTBrief
        self.recordEnvironmentInReport = recordEnvironmentInReport
        self.sourceCardProfile = sourceCardProfile
        self.verifyOnly = verifyOnly
        self.checksumRetryCount = checksumRetryCount
        self.enableSpeedLimit = enableSpeedLimit
        self.speedLimitMBps = speedLimitMBps
        self.resumedFromJournal = resumedFromJournal
        self.strictResume = strictResume
        self.ioRetryCount = ioRetryCount
        self.handoff = handoff
        self.outputPackageModes = outputPackageModes
    }

    var outputFolderName: String {
        makeOutputFolderName(project: projectName, date: createdAt, card: cardNumber)
    }

    var normalizedOutputPackageModes: [OffloadPackageMode] {
        var seen = Set<OffloadPackageMode>()
        let ordered = outputPackageModes.filter { seen.insert($0).inserted }
        return ordered.isEmpty ? [.safeCopy] : ordered
    }

    func outputFolderName(for mode: OffloadPackageMode) -> String {
        if normalizedOutputPackageModes.count == 1 {
            return outputFolderName
        }
        return "\(outputFolderName)_\(mode.folderSuffix)"
    }
}

extension OffloadSettings {
    private enum CodingKeys: String, CodingKey {
        case taskID
        case projectAssociationMode
        case linkedProjectID
        case projectName
        case cardNumber
        case operatorName
        case camera
        case location
        case notes
        case sourceURL
        case targetRoots
        case createdAt
        case generateProxies
        case transcodeProfile
        case language
        case checksumAlgorithm
        case xxHash64Implementation
        case copyBufferKB
        case writeSidecarChecksum
        case generateAscMHL
        case generateCSVLog
        case generateJSONLog
        case generateTXTBrief
        case recordEnvironmentInReport
        case sourceCardProfile
        case verifyOnly
        case checksumRetryCount
        case enableSpeedLimit
        case speedLimitMBps
        case resumedFromJournal
        case strictResume
        case ioRetryCount
        case handoff
        case outputPackageModes
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        taskID = try container.decodeIfPresent(UUID.self, forKey: .taskID) ?? UUID()
        projectAssociationMode = try container.decodeIfPresent(ProjectAssociationMode.self, forKey: .projectAssociationMode) ?? .independent
        linkedProjectID = try container.decodeIfPresent(UUID.self, forKey: .linkedProjectID)
        projectName = try container.decode(String.self, forKey: .projectName)
        cardNumber = try container.decode(String.self, forKey: .cardNumber)
        operatorName = try container.decode(String.self, forKey: .operatorName)
        camera = try container.decodeIfPresent(String.self, forKey: .camera) ?? ""
        location = try container.decodeIfPresent(String.self, forKey: .location) ?? ""
        notes = try container.decodeIfPresent(String.self, forKey: .notes) ?? ""
        sourceURL = try container.decode(URL.self, forKey: .sourceURL)
        targetRoots = try container.decode([URL].self, forKey: .targetRoots)
        createdAt = try container.decodeIfPresent(Date.self, forKey: .createdAt) ?? Date()
        generateProxies = try container.decodeIfPresent(Bool.self, forKey: .generateProxies) ?? false
        transcodeProfile = try container.decodeIfPresent(TranscodeProfile.self, forKey: .transcodeProfile) ?? .default
        language = try container.decodeIfPresent(AppLanguage.self, forKey: .language) ?? .system
        checksumAlgorithm = try container.decodeIfPresent(ChecksumAlgorithm.self, forKey: .checksumAlgorithm) ?? .xxhash64
        xxHash64Implementation = try container.decodeIfPresent(XXHash64Implementation.self, forKey: .xxHash64Implementation) ?? .automatic
        copyBufferKB = try container.decodeIfPresent(Int.self, forKey: .copyBufferKB) ?? 1024
        writeSidecarChecksum = try container.decodeIfPresent(Bool.self, forKey: .writeSidecarChecksum) ?? true
        generateAscMHL = try container.decodeIfPresent(Bool.self, forKey: .generateAscMHL) ?? true
        generateCSVLog = try container.decodeIfPresent(Bool.self, forKey: .generateCSVLog) ?? true
        generateJSONLog = try container.decodeIfPresent(Bool.self, forKey: .generateJSONLog) ?? true
        generateTXTBrief = try container.decodeIfPresent(Bool.self, forKey: .generateTXTBrief) ?? true
        recordEnvironmentInReport = try container.decodeIfPresent(Bool.self, forKey: .recordEnvironmentInReport) ?? true
        sourceCardProfile = try container.decodeIfPresent(CameraCardProfile.self, forKey: .sourceCardProfile) ?? .unknown
        verifyOnly = try container.decodeIfPresent(Bool.self, forKey: .verifyOnly) ?? false
        checksumRetryCount = try container.decodeIfPresent(Int.self, forKey: .checksumRetryCount) ?? 0
        enableSpeedLimit = try container.decodeIfPresent(Bool.self, forKey: .enableSpeedLimit) ?? false
        speedLimitMBps = try container.decodeIfPresent(Int.self, forKey: .speedLimitMBps) ?? 200
        resumedFromJournal = try container.decodeIfPresent(Bool.self, forKey: .resumedFromJournal) ?? false
        strictResume = try container.decodeIfPresent(Bool.self, forKey: .strictResume) ?? true
        ioRetryCount = try container.decodeIfPresent(Int.self, forKey: .ioRetryCount) ?? 3
        handoff = try container.decodeIfPresent(HandoffSettings.self, forKey: .handoff) ?? .init()
        outputPackageModes = try container.decodeIfPresent([OffloadPackageMode].self, forKey: .outputPackageModes) ?? [.safeCopy]
    }
}

