enum ProxyOutputKind {
    case standard
    case lutBaked
    case clean
    case burnIn
}

enum OffloadPackageLayout {
    static func isLegacyLayout(outputURL: URL) -> Bool {
        let fm = FileManager.default
        return fm.fileExists(atPath: outputURL.appendingPathComponent("01_ORIGINALS").path)
            || fm.fileExists(atPath: outputURL.appendingPathComponent("_321Doit/session.json").path)
    }

    static func originalsRoot(outputURL: URL, mode: OffloadPackageMode, cardNumber: String) -> URL {
        let root = outputURL.appendingPathComponent(
            isLegacyLayout(outputURL: outputURL) ? "01_ORIGINALS" : "MEDIA",
            isDirectory: true
        )
        switch mode {
        case .safeCopy:
            let card = sanitizedComponent(cardNumber, fallback: "CARD001")
            return root.appendingPathComponent(card, isDirectory: true)
        case .editorialDelivery:
            return root
        }
    }

    static func originalFileURL(outputURL: URL, mode: OffloadPackageMode, cardNumber: String, relativePath: String) -> URL {
        originalsRoot(outputURL: outputURL, mode: mode, cardNumber: cardNumber)
            .appendingPathComponent(relativePath)
    }

    static func reportsRoot(outputURL: URL) -> URL {
        outputURL.appendingPathComponent(
            isLegacyLayout(outputURL: outputURL) ? "03_REPORTS" : "REPORTS",
            isDirectory: true
        )
    }

    static func checksumsRoot(outputURL: URL, mode: OffloadPackageMode) -> URL {
        switch mode {
        case .safeCopy:
            return outputURL.appendingPathComponent(
                isLegacyLayout(outputURL: outputURL) ? "04_CHECKSUMS" : "CHECKSUMS",
                isDirectory: true
            )
        case .editorialDelivery:
            return reportsRoot(outputURL: outputURL)
        }
    }

    static func proxiesRoot(outputURL: URL) -> URL {
        outputURL.appendingPathComponent(
            isLegacyLayout(outputURL: outputURL) ? "02_PROXIES" : "PROXIES",
            isDirectory: true
        )
    }

    static func proxyRoot(outputURL: URL, profile: TranscodeProfile, kind: ProxyOutputKind) -> URL {
        let root = proxiesRoot(outputURL: outputURL)
        switch kind {
        case .standard:
            return root.appendingPathComponent(profile.codec.folderName, isDirectory: true)
        case .lutBaked:
            return root.appendingPathComponent("LUT_Baked", isDirectory: true)
        case .clean:
            return root.appendingPathComponent("Clean", isDirectory: true)
        case .burnIn:
            return root.appendingPathComponent("BurnIn", isDirectory: true)
        }
    }

    static func thumbnailsRoot(outputURL: URL) -> URL {
        outputURL.appendingPathComponent(
            isLegacyLayout(outputURL: outputURL) ? "06_THUMBNAILS" : "THUMBNAILS",
            isDirectory: true
        )
    }

    static func handoffRoot(outputURL: URL) -> URL {
        outputURL.appendingPathComponent(
            isLegacyLayout(outputURL: outputURL) ? "05_HANDOFF" : "INTEGRATIONS",
            isDirectory: true
        )
    }

    static func workflowRoot(outputURL: URL) -> URL {
        outputURL.appendingPathComponent(
            isLegacyLayout(outputURL: outputURL) ? "_321Doit" : ".321doit",
            isDirectory: true
        )
    }

    static func ascMHLRoot(outputURL: URL, mode: OffloadPackageMode, cardNumber: String) -> URL {
        if isLegacyLayout(outputURL: outputURL) {
            return outputURL.appendingPathComponent("ascmhl", isDirectory: true)
        }
        return originalsRoot(outputURL: outputURL, mode: mode, cardNumber: cardNumber)
            .appendingPathComponent("ascmhl", isDirectory: true)
    }

    static func targetRelativePath(outputURL: URL, fileURL: URL) -> String {
        relativePath(from: outputURL, to: fileURL)
    }
}

