    var packageMode: OffloadPackageMode
    var state: TargetState
    var copiedBytes: UInt64
    var verifiedBytes: UInt64
    var transcodeProgress: Double?
    var error: String?
    var bytesPerSecond: Double = 0

    var displayName: String {
        let rootName = rootURL.lastPathComponent.isEmpty ? rootURL.path : rootURL.lastPathComponent
        return "\(rootName) · \(packageMode.folderSuffix)"
    }
}

struct FileTargetResult: Equatable {
    var rootPath: String
    var outputPath: String
    var copied: Bool
    var verified: Bool
    var hash: String?
    var error: String?
}

struct FileCopyRecord: Identifiable, Equatable {
    let id = UUID()
    var relativePath: String
    var size: UInt64
    var modifiedAt: Date
    var sourceHash: String
    var targetResults: [FileTargetResult]
}

struct OffloadSnapshot: Equatable {
    var message: String
    var totalFiles: Int
    var completedFiles: Int
    var totalBytes: UInt64
    var copiedBytes: UInt64
    var startedAt: Date?
    var targets: [TargetProgress]
    var recentLog: String?
    var averageBytesPerSecond: Double = 0
    var currentBytesPerSecond: Double = 0
    var etaSeconds: TimeInterval?

    var progress: Double {
        guard totalBytes > 0 else { return 0 }
        return min(1, Double(copiedBytes) / Double(totalBytes))
    }
}

struct TargetReport: Equatable {
    var rootURL: URL
    var outputURL: URL
    var packageMode: OffloadPackageMode
    var state: TargetState
    var copiedBytes: UInt64
    var verifiedBytes: UInt64
    var error: String?
    var mhlURL: URL?
    var pdfURL: URL?
    var csvURL: URL?
    var jsonURL: URL?
    var txtURL: URL?
    var sidecarURL: URL?
    var proxyURL: URL?
    var proxyFilesCreated: Int
    var proxyErrors: [String]
    var handoff: HandoffOutput? = nil
}

/// Where 321Doit wrote post-handoff packages for one target.
struct HandoffOutput: Equatable {
    var rootURL: URL                 // 05_HANDOFF dir
    var manifestURL: URL?
    var resolveScriptURL: URL?       // resolve_import.py
    var resolveJSONURL: URL?         // resolve_import.json
    var fcpxmldURL: URL?             // PROJECT.fcpxmld
    var fcpxmlCompatURL: URL?        // PROJECT_compat.fcpxml
    var warnings: [String] = []
}

struct OffloadReport: Equatable {
    var settings: OffloadSettings
    var startedAt: Date
    var endedAt: Date
    var totalFiles: Int
    var totalBytes: UInt64
    var files: [FileCopyRecord]
    var targets: [TargetReport]
    var logs: [String]

    var successfulTargets: [TargetReport] {
        targets.filter { $0.state == .completed }
    }
}

enum OffloadError: LocalizedError {
    case missingRequiredFields
    case sourceUnavailable
    case noTargets
    case tooManyTargets
    case noFiles
    case duplicateTarget(URL)
    case duplicateOutput(URL)
    case nestedPath(String)
    case unsafeSourceLink(String)
    case insufficientSpace(target: URL, needed: UInt64, available: UInt64)
    case fat32LargeFile(target: URL, file: String, size: UInt64)
    case reportGenerationFailed([String])
    case allTargetsFailed

    var errorDescription: String? {
        switch self {
        case .missingRequiredFields:
            return "Project, card, operator, source and destination are all required."
        case .sourceUnavailable:
            return "Source does not exist or is not a folder."
        case .noTargets:
            return "Select at least one destination."
        case .tooManyTargets:
            return "This version supports at most 3 destinations."
        case .noFiles:
            return "No files to copy in the source."
        case .duplicateTarget(let url):
            return "Destination listed twice: \(url.path)"
        case .duplicateOutput(let url):
            return "Destination already has a folder with this card name; refused to overwrite: \(url.path)"
        case .nestedPath(let message):
            return message
        case .unsafeSourceLink(let path):
            return "Source contains a symbolic link or a path outside the selected source folder: \(path)"
        case .insufficientSpace(let target, let needed, let available):
            return "\(target.path) does not have enough free space; needs \(formatBytes(needed)), available \(formatBytes(available))."
        case .fat32LargeFile(let target, let file, let size):
            return "\(target.path) looks like FAT32 and cannot hold a single file larger than 4GB: \(file) (\(formatBytes(size))). Use exFAT or APFS instead."
        case .reportGenerationFailed(let messages):
            return "Media was copied, but one or more destination reports failed: \(messages.joined(separator: "; "))"
        case .allTargetsFailed:
            return "All destinations failed; the task did not complete."
        }
    }
}

let macJunkExact: Set<String> = [
    ".DS_Store",
    ".AppleDouble",
    ".LSOverride",
    ".Spotlight-V100",
    ".TemporaryItems",
    ".Trashes",
    ".fseventsd",
    ".DocumentRevisions-V100",
    ".VolumeIcon.icns",
    ".apdisk",
    ".localized",
    "__MACOSX",
    "Icon\r"
]

func isMacJunk(_ name: String) -> Bool {
    macJunkExact.contains(name) || name.hasPrefix("._")
}

func sanitizedComponent(_ value: String, fallback: String) -> String {
    let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
    let replaced = trimmed.unicodeScalars.map { scalar -> Character in
        if CharacterSet.alphanumerics.contains(scalar) || scalar == "_" || scalar == "-" {
            return Character(scalar)
        }
        return "_"
    }
    let compact = String(replaced)
        .replacingOccurrences(of: "__+", with: "_", options: .regularExpression)
        .trimmingCharacters(in: CharacterSet(charactersIn: "_-"))
    return compact.isEmpty ? fallback : compact.uppercased()
}

/// RFC 4180-style CSV escaping plus spreadsheet formula neutralization.
/// Project names, notes, and card file names are untrusted input; Excel and
/// Numbers interpret cells beginning with these characters as formulas.
func spreadsheetSafeCSVField(_ value: String, alwaysQuote: Bool = false) -> String {
    var safe = value
    if let first = safe.first, "=+-@\t\r".contains(first) {
        safe = "'" + safe
    }
    let escaped = safe.replacingOccurrences(of: "\"", with: "\"\"")
    if alwaysQuote || escaped.contains(",") || escaped.contains("\n") || escaped.contains("\"") {
        return "\"\(escaped)\""
    }
    return escaped
}

func makeOutputFolderName(project: String, date: Date, card: String) -> String {
    let projectPart = sanitizedComponent(project, fallback: "PROJECT")
    let cardPart = sanitizedComponent(card, fallback: "CARD")
    return "\(projectPart)_\(AppDateFormatters.outputFolderString(date))_\(cardPart)"
}

func formatBytes(_ bytes: UInt64) -> String {
    let units = ["B", "KB", "MB", "GB", "TB", "PB"]
    var value = Double(bytes)
    var index = 0
    while value >= 1024 && index < units.count - 1 {
        value /= 1024
        index += 1
    }
    if index == 0 || value >= 10 {
        return "\(Int(value.rounded())) \(units[index])"
    }
    return String(format: "%.1f %@", value, units[index])
}

func escapeXML(_ value: String) -> String {
    value
        .replacingOccurrences(of: "&", with: "&amp;")
        .replacingOccurrences(of: "<", with: "&lt;")
        .replacingOccurrences(of: ">", with: "&gt;")
        .replacingOccurrences(of: "\"", with: "&quot;")
        .replacingOccurrences(of: "'", with: "&apos;")
}

func iso8601String(_ date: Date) -> String {
    AppDateFormatters.iso8601String(date)
}

private enum AppDateFormatters {
    private static let outputFolderLock = NSLock()
    private static let outputFolderFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "yyyyMMdd"
        return formatter
    }()

    private static let isoLock = NSLock()
    private static let isoFormatter: ISO8601DateFormatter = {
        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return formatter
    }()

    static func outputFolderString(_ date: Date) -> String {
        outputFolderLock.lock()
        defer { outputFolderLock.unlock() }
        return outputFolderFormatter.string(from: date)
    }

    static func iso8601String(_ date: Date) -> String {
        isoLock.lock()
        defer { isoLock.unlock() }
        return isoFormatter.string(from: date)
    }
}

func enumerateSourceFiles(at sourceURL: URL) throws -> [SourceFile] {
    let fileManager = FileManager.default
    var isDirectory: ObjCBool = false
    guard fileManager.fileExists(atPath: sourceURL.path, isDirectory: &isDirectory), isDirectory.boolValue else {
        throw OffloadError.sourceUnavailable
    }

    let keys: Set<URLResourceKey> = [
        .isDirectoryKey,
        .isRegularFileKey,
        .isSymbolicLinkKey,
        .fileSizeKey,
        .contentModificationDateKey
    ]
    guard let enumerator = fileManager.enumerator(
        at: sourceURL,
        includingPropertiesForKeys: Array(keys),
        options: [.skipsPackageDescendants]
    ) else {
        throw OffloadError.sourceUnavailable
    }

    var files: [SourceFile] = []
    let resolvedRoot = sourceURL.resolvingSymlinksInPath().standardizedFileURL
    for case let fileURL as URL in enumerator {
        let values = try fileURL.resourceValues(forKeys: keys)
        if values.isSymbolicLink == true {
            throw OffloadError.unsafeSourceLink(relativePath(from: sourceURL, to: fileURL))
        }
        if isMacJunk(fileURL.lastPathComponent) {
            if values.isDirectory == true {
                enumerator.skipDescendants()
            }
            continue
        }

        if values.isDirectory == true {
            continue
        }
        guard values.isRegularFile == true else {
            continue
        }

        let resolvedFile = fileURL.resolvingSymlinksInPath().standardizedFileURL
        guard isSameOrNested(resolvedFile, under: resolvedRoot) else {
            throw OffloadError.unsafeSourceLink(relativePath(from: sourceURL, to: fileURL))
        }

        let rel = relativePath(from: sourceURL, to: fileURL)
        let size = UInt64(values.fileSize ?? 0)
        files.append(SourceFile(
            url: fileURL,
            relativePath: rel,
            size: size,
            modifiedAt: values.contentModificationDate ?? Date(timeIntervalSince1970: 0)
        ))
    }

    return files.sorted { $0.relativePath.localizedStandardCompare($1.relativePath) == .orderedAscending }
}

func relativePath(from root: URL, to file: URL) -> String {
    let rootPath = root.standardizedFileURL.path
    let filePath = file.standardizedFileURL.path
    if filePath == rootPath {
        return file.lastPathComponent
    }
    let prefix = rootPath.hasSuffix("/") ? rootPath : "\(rootPath)/"
    if filePath.hasPrefix(prefix) {
        return String(filePath.dropFirst(prefix.count))
    }
    return file.lastPathComponent
}

func isSameOrNested(_ child: URL, under parent: URL) -> Bool {
    let childPath = child.standardizedFileURL.path
    let parentPath = parent.standardizedFileURL.path
    if childPath == parentPath {
        return true
    }
    let prefix = parentPath.hasSuffix("/") ? parentPath : "\(parentPath)/"
    return childPath.hasPrefix(prefix)
}

func availableCapacity(at url: URL) -> UInt64 {
    let keys: Set<URLResourceKey> = [
        .volumeAvailableCapacityForImportantUsageKey,
        .volumeAvailableCapacityKey
    ]
    if let values = try? url.resourceValues(forKeys: keys) {
        if let important = values.volumeAvailableCapacityForImportantUsage, important > 0 {
            return UInt64(important)
        }
        if let regular = values.volumeAvailableCapacity, regular > 0 {
            return UInt64(regular)
        }
    }
    return 0
}
